function wp711T(key,vars={}){
  const lang=WP711_I18N[wp71LanguageProfile?.ui] ? wp71LanguageProfile.ui : 'en';
  let value=(WP711_I18N[lang]&&WP711_I18N[lang][key])||WP711_I18N.en[key]||key;
  Object.entries(vars).forEach(([k,v])=>value=value.replaceAll(`{${k}}`,String(v)));
  return value;
}
function wp711ReadProfile(){
  let row={ui:'tr',support:'tr',target:localStorage.getItem(ACTIVE_COURSE_KEY)||'en',experience:'standard',complete:false};
  try{row={...row,...JSON.parse(localStorage.getItem(WP71_SETTINGS_KEY)||'{}')}}catch{}
  if(!WP711_LANGS.includes(row.support))row.support=WP711_LANGS.includes(row.ui)?row.ui:'tr';
  if(!WP711_LANGS.includes(row.target))row.target='en';
  if(row.support===row.target)row.target=row.support==='en'?'es':'en';
  row.ui=row.support;return row;
}
