wp71Concepts=null;
wp71LoadConcepts=async function(){
  if(wp71Concepts)return wp71Concepts;
  const response=await fetch(`${WP711_CONCEPT_FILE}?v=${VERSION}`,{cache:'no-store'});
  if(!response.ok)throw new Error(WP711_CONCEPT_FILE);
  wp71Concepts=await response.json();return wp71Concepts;
};
wp71ConceptToLegacy=function(c,target=wp71Target(),support=wp71Support()){
  const term=c.terms?.[target]||c.terms?.en||'',meaning=c.terms?.[support]||c.terms?.en||'',supportUsage=c.usage?.[support]||c.usage?.en||'',targetExample=c.examples?.[target]||c.examples?.en||'',supportExample=c.examples?.[support]||c.examples?.en||'';
  const id=Number(c.legacy_ids?.en)||Number(String(c.concept_id||'').match(/\d+$/)?.[0])||0;
  return {id,concept_id:c.concept_id,english:term,word:term,pronunciation:'',meaningTr:meaning,meaning:`${meaning} ★★★★★`,usage:`• ${supportUsage}`,example:`• ${targetExample}`,translation:`• ${supportExample}`,synonyms:'',opposite:'',family:'',phrase:'',collocations:'',notes:'',cefr:`● ${c.level||'A1'}`,level:c.level||'A1',type:`● ${String(c.part_of_speech||'word')}`,group:`Clean Core · ${c.topic||'Core'}`,topic:c.topic||'Core',target_lang:target,support_lang:support,content_origin:c.content_origin,license:c.license,review_status:c.review_status,commercial_safe:c.commercial_safe===true,content_hash:c.content_hash};
};
loadCourseWords=async function(course=activeCourse){
  const support=wp71Support();
  if(courseWordCache[course]){words=courseWordCache[course];return words}
  if((course==='ru'||course==='uz')&&support==='tr'){
    const meta=COURSES[course],response=await fetch(`${meta.file}?v=${VERSION}`,{cache:'no-store'});if(!response.ok)throw new Error(meta.file);
    const raw=await response.json(),data=raw.map(row=>normalizeCourseRecord(row,course));courseWordCache[course]=data;words=data;if(course==='ru'&&!russianAlphabet.length)await loadRussianAlphabet();return data;
  }
  const concepts=await wp71LoadConcepts(),data=concepts.map(c=>wp71ConceptToLegacy(c,course,support));courseWordCache[course]=data;words=data;return data;
};

