function wp711TranslateLegacy(root=document.body){
  if(!root||wp71LanguageProfile.ui==='tr')return;
  const lang=wp71LanguageProfile.ui,walker=document.createTreeWalker(root,NodeFilter.SHOW_TEXT,{acceptNode(node){if(!node.parentElement||['SCRIPT','STYLE','TEXTAREA','OPTION'].includes(node.parentElement.tagName))return NodeFilter.FILTER_REJECT;return node.nodeValue.trim()?NodeFilter.FILTER_ACCEPT:NodeFilter.FILTER_REJECT}}),nodes=[];while(walker.nextNode())nodes.push(walker.currentNode);
  nodes.forEach(node=>{const raw=node.nodeValue,trim=raw.trim(),en=WP711_TR_EN[trim];if(!en)return;const key=WP711_EN_KEY[en],local=key?(WP711_I18N[lang]?.[key]||en):en;node.nodeValue=raw.replace(trim,local)});
  $$('input[placeholder],textarea[placeholder]').forEach(el=>{const en=WP711_TR_EN[el.placeholder];if(en)el.placeholder=en});
};
